using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 removes Discriminator from the id by default.
        // Existing docs use "Blog|1" format. Restore the old behavior:
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Breaking change 2: EF Core 9 renamed "Discriminator" → "$type".
        // Existing docs have "Discriminator". Restore the old property name:
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Cosmos DB does not support indexes via EF Core.
        // HasIndex() now throws at model validation in EF Core 9. Removed.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

